// src/app/api/badge/route.tsx
import { NextRequest, NextResponse } from 'next/server';
export const runtime = 'nodejs';


const BADGE_SEAL = 'data:image/png;base64,';

const MARK_WHITE_PARTS: string[] = [
  "",
  "",
  "",
  "",
  "",
  "06pPqNeAngghnfTz6V3YAXCCvDP15HZyO7l9pbcVK1ZIiCg/9dRTX4mXO55QGyJKJ1E4cvAIAMC777475NNPO1Z++OH7805a4GGAh4jS1q3vzOzq2reNUhN7e7txx44Pbz9pkoexMUaILEtIKQVNU0GWif8kKl/cCmUAgO3bty/R9fy2j3d+tGHz5g0N/x8TmPAIQ3R0mQAAAABJRU5ErkJggg==",
];
const MARK_WHITE = `data:image/png;base64,${MARK_WHITE_PARTS.join("")}`;

const MARK_BLACK_PARTS: string[] = [
  "",
  "",
  "",
  "",
  "",
  "",
];
const MARK_BLACK = `data:image/png;base64,${MARK_BLACK_PARTS.join("")}`;

const THEMES: Record<string, {
  bg: string; headerBg: string; headerText: string;
  accent: string; accentDim: string;
  bodyText: string; statBg: string;
  border: string; dark: boolean;
}> = {
  'circuit-anim': { bg:'#081420', headerBg:'#04090f', headerText:'#00e5ff', accent:'#00e5ff', accentDim:'#1a5060', bodyText:'#d0eef5', statBg:'#0a1f32', border:'#0d3040', dark:true },
  'circuit':      { bg:'#08121e', headerBg:'#030a12', headerText:'#00bcd4', accent:'#00bcd4', accentDim:'#0d3a42', bodyText:'#cce8ee', statBg:'#091c2a', border:'#0d3040', dark:true },
  'parchment':    { bg:'#f5f0e8', headerBg:'#8b1a1a', headerText:'#ffffff', accent:'#8b1a1a', accentDim:'#6b3a1a', bodyText:'#0d0a07', statBg:'#ede6d4', border:'#c9b882', dark:false },
  'aurora':       { bg:'#080c1a', headerBg:'#04030e', headerText:'#a78bfa', accent:'#a78bfa', accentDim:'#7060a0', bodyText:'#ddd6fe', statBg:'#0a081c', border:'#201840', dark:true },
  'base':         { bg:'#e8f0fe', headerBg:'#1a56db', headerText:'#ffffff', accent:'#1a56db', accentDim:'#1a56db', bodyText:'#0d1b2a', statBg:'#d0e0fc', border:'#93b4f5', dark:false },
  'gold':         { bg:'#0e0b06', headerBg:'#070503', headerText:'#d4af37', accent:'#d4af37', accentDim:'#a08828', bodyText:'#e8ddc0', statBg:'#120e07', border:'#2a2010', dark:true },
  'silver':       { bg:'#0c0c10', headerBg:'#070709', headerText:'#c0c8d8', accent:'#c0c8d8', accentDim:'#8090a8', bodyText:'#e0e8f0', statBg:'#101018', border:'#2a3040', dark:true },
  'bronze':       { bg:'#0e0803', headerBg:'#080400', headerText:'#cd7f32', accent:'#cd7f32', accentDim:'#8a5520', bodyText:'#e8d0b0', statBg:'#120a04', border:'#2a1808', dark:true },
  'bitcoin':      { bg:'#f7931a', headerBg:'#c97a10', headerText:'#ffffff', accent:'#ffffff', accentDim:'rgba(255,255,255,0.5)', bodyText:'#1a0800', statBg:'rgba(0,0,0,0.15)', border:'rgba(255,255,255,0.3)', dark:false },
};

function esc(s: string): string {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function truncate(s: string, n: number) {
  return s.length > n ? s.slice(0, n - 1) + '\u2026' : s;
}

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);

  // Permanent link support: ?uid=0x... fetches from EAS
  let themeKey: string;
  let achievement: string;
  let chain: string;
  let txHash: string;
  let agentId: string;

  const uid_param = searchParams.get('uid');
  if (uid_param) {
    const { fetchAttestation, fetchAttestationByTx } = await import('@/lib/eas');
    // Try as attestation UID first, fall back to TX hash lookup
    const data = await fetchAttestation(uid_param) || await fetchAttestationByTx(uid_param);
    if (!data) {
      return new NextResponse('Attestation not found', { status: 404 });
    }
    themeKey    = searchParams.get('theme') || 'circuit-anim';
    achievement = truncate(esc(data.achievement), 38);
    chain       = searchParams.get('chain') || 'Base';
    txHash      = data.txHash;
    agentId     = data.recipient.slice(0,6);
  } else {
    themeKey    = searchParams.get('theme') || 'circuit-anim';
    achievement = truncate(esc(searchParams.get('achievement') || 'Verified Statement'), 38);
    chain       = esc(searchParams.get('chain') || 'Base');
    txHash      = searchParams.get('txHash') || '';
    agentId     = esc(searchParams.get('agentId') || '????');
  }
  const uid         = txHash ? '0x' + txHash.slice(2,6) + '\u2026' + txHash.slice(-4) : '0x????\u2026????';

  const t    = THEMES[themeKey] ?? THEMES['circuit-anim'];
  const mark = (themeKey === 'base' || themeKey === 'bitcoin') ? MARK_WHITE : (t.dark ? MARK_WHITE : MARK_BLACK);

  const isCircuit  = themeKey === 'circuit-anim' || themeKey === 'circuit';
  const traceColor = themeKey === 'circuit-anim' ? '#00e5ff' : '#00bcd4';
  const traceOp    = themeKey === 'circuit-anim' ? '0.25' : '0.15';

  let decoration = '';
  if (isCircuit) {
    decoration = `
    <g stroke="${traceColor}" stroke-width="0.7" fill="none" opacity="${traceOp}">
      <polyline points="0,40 18,40 26,48 26,80"/>
      <polyline points="240,40 222,40 214,48 214,80"/>
      <polyline points="0,160 18,160 26,152 26,130"/>
      <polyline points="240,160 222,160 214,152 214,130"/>
    </g>
    <g fill="${traceColor}" opacity="0.5">
      <circle cx="26" cy="80" r="2.5"/>
      <circle cx="214" cy="80" r="2.5"/>
      <circle cx="26" cy="130" r="2.5"/>
      <circle cx="214" cy="130" r="2.5"/>
    </g>`;
  } else if (themeKey === 'gold') {
    decoration = `
    <polygon points="120,30 200,105 120,180 40,105" stroke="${t.accent}" stroke-width="0.6" fill="none" opacity="0.07"/>
    <polygon points="120,55 178,105 120,155 62,105" stroke="${t.accent}" stroke-width="0.3" fill="none" opacity="0.05"/>`;
  } else if (themeKey === 'silver') {
    const hex = (cx: number, cy: number, r: number) => {
      const pts = Array.from({length:6},(_,i)=>{const a=Math.PI/180*(60*i-30);return `${(cx+r*Math.cos(a)).toFixed(1)},${(cy+r*Math.sin(a)).toFixed(1)}`;}).join(' ');
      return `<polygon points="${pts}" stroke="${t.accent}" stroke-width="0.5" fill="none" opacity="0.08"/>`;
    };
    decoration = hex(30,75,22)+hex(55,75,22)+hex(185,75,22)+hex(210,75,22);
  } else if (themeKey === 'bronze') {
    decoration = `
    <g fill="${t.accent}" opacity="0.025">
      <circle cx="30" cy="80" r="30"/>
      <circle cx="210" cy="120" r="25"/>
      <circle cx="120" cy="160" r="35"/>
    </g>`;
  } else if (themeKey === 'parchment') {
    decoration = `
    <g stroke="#c9b882" stroke-width="0.4" opacity="0.35">
      <line x1="8" y1="38" x2="232" y2="38"/>
      <line x1="8" y1="192" x2="232" y2="192"/>
    </g>`;
  } else if (themeKey === 'aurora') {
    decoration = `
    <radialGradient id="ag" cx="50%" cy="50%" r="50%">
      <stop offset="0%" stop-color="${t.accent}" stop-opacity="0.08"/>
      <stop offset="100%" stop-color="${t.accent}" stop-opacity="0"/>
    </radialGradient>
    <ellipse cx="120" cy="100" rx="90" ry="75" fill="url(#ag)"/>`;
  } else if (themeKey === 'base') {
    decoration = `
    <g stroke="${t.accent}" stroke-width="0.25" opacity="0.12">
      ${[60,120,180].map(x=>`<line x1="${x}" y1="38" x2="${x}" y2="192"/>`).join('')}
      ${[80,120,160].map(y=>`<line x1="8" y1="${y}" x2="232" y2="${y}"/>`).join('')}
    </g>
    <rect x="0" y="38" width="3" height="154" fill="${t.accent}" opacity="0.4"/>`;
  } else if (themeKey === 'bitcoin') {
    decoration = `
    <g font-family="Arial,sans-serif" font-weight="bold" fill="white" opacity="0.1">
      <text x="8"   y="90"  font-size="40" transform="rotate(-15,8,90)">&#x20BF;</text>
      <text x="175" y="75"  font-size="35" transform="rotate(-15,175,75)">&#x20BF;</text>
      <text x="90"  y="185" font-size="30" transform="rotate(-15,90,185)">&#x20BF;</text>
      <text x="155" y="170" font-size="38" transform="rotate(-15,155,170)">&#x20BF;</text>
      <text x="30"  y="165" font-size="28" transform="rotate(-15,30,165)">&#x20BF;</text>
    </g>`;
  }

  const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg width="240" height="200" viewBox="0 0 240 200" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <clipPath id="bc"><rect width="240" height="200" rx="12" ry="12"/></clipPath>
  </defs>

  <rect width="240" height="200" rx="12" ry="12" fill="${t.bg}" stroke="${t.border}" stroke-width="1"/>
  <g clip-path="url(#bc)">${decoration}</g>

  <!-- Header -->
  <rect x="0" y="0" width="240" height="36" rx="12" ry="12" fill="${t.headerBg}"/>
  <rect x="0" y="24" width="240" height="12" fill="${t.headerBg}"/>
  <!-- Mark logo in header (left) -->
  <image href="${mark}" x="20" y="10" width="20" height="20"
    preserveAspectRatio="xMidYMid meet" opacity="0.9"/>
  <text x="126" y="22" font-family="monospace" font-size="7.5" font-weight="bold"
    fill="${t.headerText}" text-anchor="middle" letter-spacing="1.5">THESEALER.XYZ · OFFICIAL</text>

  <!-- Seal -->
  <circle cx="120" cy="95" r="44" fill="${t.accent}" opacity="${t.dark ? '0.04' : '0'}"/>
  <image href="${BADGE_SEAL}" x="78" y="53" width="84" height="84"
    preserveAspectRatio="xMidYMid meet"/>

  <!-- Statement -->
  <text x="120" y="152" font-family="Georgia,serif" font-size="9.5" font-style="italic"
    fill="${t.bodyText}" text-anchor="middle" opacity="0.85">${achievement}</text>

  <!-- Bottom bar -->
  <rect x="8" y="160" width="224" height="32" rx="4"
    fill="${t.statBg}" stroke="${t.border}" stroke-width="0.8"/>

  <!-- Bottom bar: 4 columns -->
  <rect x="8" y="160" width="224" height="32" rx="4"
    fill="${t.statBg}" stroke="${t.border}" stroke-width="0.8"/>

  <!-- Dividers -->
  <line x1="64" y1="163" x2="64" y2="189" stroke="${t.border}" stroke-width="0.6"/>
  <line x1="120" y1="163" x2="120" y2="189" stroke="${t.border}" stroke-width="0.6"/>
  <line x1="176" y1="163" x2="176" y2="189" stroke="${t.border}" stroke-width="0.6"/>

  <!-- Col 1: Chain pill -->
  <text x="36" y="170" font-family="monospace" font-size="5.5" font-weight="bold"
    fill="${t.accent}" text-anchor="middle" opacity="0.6">${chain} · EAS</text>
  <rect x="13" y="174" width="46" height="13" rx="6"
    fill="${t.bg}" stroke="${t.accent}" stroke-width="0.7"/>
  <text x="36" y="184" font-family="monospace" font-size="6" font-weight="bold"
    fill="${t.accent}" text-anchor="middle">VERIFIED</text>

  <!-- Col 2: TX hash -->
  <text x="92" y="170" font-family="monospace" font-size="5.5"
    fill="${t.accent}" text-anchor="middle" opacity="0.6">TX HASH</text>
  <text x="92" y="182" font-family="monospace" font-size="6"
    fill="${t.accent}" text-anchor="middle" opacity="0.9">${uid}</text>

  <!-- Col 3: Agent ID -->
  <text x="148" y="170" font-family="monospace" font-size="5.5"
    fill="${t.accent}" text-anchor="middle" opacity="0.6">AGENT</text>
  <text x="148" y="182" font-family="monospace" font-size="7" font-weight="bold"
    fill="${t.accent}" text-anchor="middle">#${agentId}</text>

  <!-- Col 4: Date -->
  <text x="204" y="170" font-family="monospace" font-size="5.5"
    fill="${t.accent}" text-anchor="middle" opacity="0.6">ISSUED</text>
  <text x="204" y="182" font-family="monospace" font-size="6"
    fill="${t.accent}" text-anchor="middle">${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}</text>

</svg>`;

  return new NextResponse(svg, {
    status: 200,
    headers: { 'Content-Type': 'image/svg+xml', 'Cache-Control': 'no-store' },
  });
}
